function largestDivisibleSubset(nums) {
    nums.sort((a, b) => a - b);
    const n = nums.length;
    const count = new Array(n).fill(1);
    const prev = new Array(n).fill(-1);
    let max_idx = 0;

    for (let i = 1; i < n; i++) {
        for (let j = 0; j < i; j++) {
            if (nums[i] % nums[j] === 0 && count[i] < count[j] + 1) {
                count[i] = count[j] + 1;
                prev[i] = j;
            }
        }
        if (count[max_idx] < count[i]) {
            max_idx = i;
        }
    }

    const res = [];
    for (let i = max_idx; i >= 0; i = prev[i]) {
        res.push(nums[i]);
    }

    return res;
}
```

    1. Sort the input array.
2. Initialize two arrays: count and prev, both with the same length as the input array.
   - count will store the length of the largest subsets ending at index i.
   - prev stores the index of the previous element in the largest subset.
3. Initialize max_idx to store the index of the maximum count.
4. Loop through the sorted array, and for each element, compare it with its previous elements.
   - If it is divisible by the previous element, update the count and prev arrays accordingly.
5. After looping and updating the arrays, use max_idx to trace back the elements forming the largest subset.
6. Return the largest subset.

