import java.util.*;

public List<Integer> largestDivisibleSubset(int[] nums) {
    Arrays.sort(nums);
    int n = nums.length;
    int[] count = new int[n];
    int[] prev = new int[n];
    int max_idx = 0;
    Arrays.fill(prev, -1);
    Arrays.fill(count, 1);

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (nums[i] % nums[j] == 0 && count[i] < count[j] + 1) {
                count[i] = count[j] + 1;
                prev[i] = j;
            }
        }
        if (count[max_idx] < count[i]) max_idx = i;
    }

    List<Integer> res = new ArrayList<>();
    for (int i = max_idx; i >= 0; i = prev[i]) {
        res.add(nums[i]);
    }

    return res;
}
```

